// ── Ben Eater per-module lesson boards regression ────────────────────────────
// Guards js/onramp-beneater-boards.js (generated by
// helperscripts/generate_ben_eater_cpu.py --modules), the boards shown by the
// onramp "Ben Eater 8-bit CPU" course, plus the course definition itself.
//
// The boards are isolated "anatomy" views — a lone module has no bus/control
// rails feeding it — so the checks here are structural: every board must
// deserialize, evaluate without a short, keep its chips powered, and carry the
// components the lesson text points at. The full CPU's behaviour is covered by
// the example itself; these only need to be safe to put in front of a learner.
//
// Run:  node js/debug/scenarios/beneater-module-boards.mjs   (exits non-zero on failure)

import { CircuitHarness } from '../harness.mjs';
import { BENEATER_MODULE_BOARDS } from '../../onramp-beneater-boards.js';
import { BENEATER_LESSONS } from '../../onramp-lessons-beneater.js';

let failures = 0;
function check(name, pass, detail = '') {
  console.log(`  ${pass ? '✓' : '✗'} ${name}${detail ? '   (' + detail + ')' : ''}`);
  if (!pass) failures++;
}

const chipIds = (board) =>
  board.components.filter(c => c.type === 'chip').map(c => c.chipId).sort();

// ── 1. Every module board loads and evaluates without a short ────────────────
{
  console.log('\n1. Module boards (load + evaluate + no shorts)');
  for (const [key, board] of Object.entries(BENEATER_MODULE_BOARDS)) {
    let ok = true, detail = '';
    try {
      const h = CircuitHarness.fromJSON(board);
      h.evaluate();
      if (h.hasShort) { ok = false; detail = 'short circuit'; }
    } catch (e) {
      ok = false; detail = e.message;
    }
    check(`${key} loads + evaluates`, ok, detail);
  }
}

// ── 2. Boards contain the chips the lesson prose describes ───────────────────
{
  console.log('\n2. Chip rosters match the lesson text');
  const expect = {
    clock:   ['555', '74x04', '74x08'],
    pc:      ['74x161', '74x245'],
    mar:     ['74x173'],
    ram:     ['74x00', '74x157', '74x189', '74x189', '74x245'],
    ir:      ['74x173', '74x173', '74x245'],
    control: ['28C16', '28C16', '74x04', '74x138', '74x161'],
    a:       ['74x173', '74x173', '74x245'],
    alu:     ['74x245', '74x283', '74x283', '74x32', '74x86', '74x86'],
    b:       ['74x173', '74x173'],
    flags:   ['74x173'],
    output:  ['28C16', '74x107', '74x139', '74x377'],
  };
  for (const [key, chips] of Object.entries(expect)) {
    const got = chipIds(BENEATER_MODULE_BOARDS[key]);
    check(`${key} chips`, JSON.stringify(got) === JSON.stringify(chips),
          `got ${got.join(',')}`);
  }
  // Reset is chip-less: exactly one push button.
  const reset = BENEATER_MODULE_BOARDS.reset;
  check('reset is a single push button',
        reset.components.length === 1 && reset.components[0].type === 'push_button');
}

// ── 3. Register modules carry their LED readouts ─────────────────────────────
{
  console.log('\n3. LED readout panels');
  const ledCounts = { pc: 4, mar: 4, ir: 8, a: 8, alu: 8, b: 8, flags: 2 };
  for (const [key, n] of Object.entries(ledCounts)) {
    const leds = BENEATER_MODULE_BOARDS[key].components.filter(c => c.type === 'led');
    check(`${key} has ${n} LEDs`, leds.length === n, `got ${leds.length}`);
  }
}

// ── 4. Course definition sanity ──────────────────────────────────────────────
{
  console.log('\n4. Course definition (js/onramp-lessons-beneater.js)');
  check('14 lessons', BENEATER_LESSONS.length === 14, `got ${BENEATER_LESSONS.length}`);
  let stepsOk = true, quizOk = true;
  for (const lesson of BENEATER_LESSONS) {
    for (const step of lesson.steps) {
      if (!step.id || !step.content) stepsOk = false;
      if (step.boardState && step.fullWidth) stepsOk = false;
      // A step gated by a validator must wire up its quiz handlers.
      if (step.validate && !step.setup) quizOk = false;
      // Quiz markup must contain exactly one correct answer.
      if (step.content.includes('quiz-option')) {
        const n = (step.content.match(/data-answer="correct"/g) || []).length;
        if (n !== 1) quizOk = false;
      }
    }
  }
  check('every step has id + content, no boardState/fullWidth conflicts', stepsOk);
  check('every quiz has a setup and exactly one correct answer', quizOk);
  // Module lessons 2-13 each show a real board somewhere.
  const boardLessons = BENEATER_LESSONS.slice(1, 13);
  check('lessons 2-13 each carry a module board',
        boardLessons.every(l => l.steps.some(s => s.boardState)));
}

console.log(failures === 0 ? '\nAll checks passed.' : `\n${failures} check(s) FAILED.`);
process.exit(failures === 0 ? 0 : 1);
